INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (31, '科技爱好者周刊（第 388 期）：测试是新的护城河', '这里记录每周值得分享的科技内容，周五发布。...', '<p>这里记录每周值得分享的科技内容，周五发布。</p>
        <p>本杂志<a href="https://github.com/ruanyf/weekly">开源</a>，欢迎<a href="https://github.com/ruanyf/weekly/issues">投稿</a>。另有<a href="https://github.com/ruanyf/weekly/issues/9088">《谁在招人》</a>服务，发布程序员招聘信息。合作请<a href="mailto:yifeng.ruan@gmail.com">邮件联系</a>（yifeng.ruan@gmail.com）。</p>
<h2>封面图</h2>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030804.webp" title="" /></p>
<p>重庆涪陵某景区架设了世界首座"巨石索桥"，桥面就是一块块巨石，一不小心就会踏空。（<a href="https://www.cbg.cn/a/77561/20260214/7b37135efeb74f0fbbaf272a9b7f6ae0.html">via</a>）</p>
<h2>测试是新的护城河</h2>
<p><a href="https://nextjs.org">Next.js</a> 是目前排名第一的 JS 框架。平时遇到的 JS 全栈应用，我估计，一半用它开发。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022808.webp" title="" /></p>
<p>两周前，这个框架被一则新闻颠覆了。</p>
<p>一个 Cloudflare 工程师<a href="https://blog.cloudflare.com/vinext/">宣布</a>，<strong>他只用一个星期就用 AI 重新实现了 Next.js</strong>，起名为 <a href="https://vinext.io/">vinext</a>。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022809.webp" title="" /></p>
<p>事实上，一天就生成产品原型了，后面几天只是在完善。</p>
<blockquote>
  <p>"真正动手是2月13日，当天晚上，基本功能已经实现。第二天下午，11个路由器做好了10个。第三天，已经部署到我们的服务器，实现了完整的客户端水合。</p>
<p>接下来的几天，主要进行安全加固：修复极端情况，扩展测试套件，提升 API 覆盖率至 94%。"</p>
</blockquote>
<p>这个新的实现，比原版 Next.js 性能更好。</p>
<blockquote>
  <p>"早期基准测试中，构建速度提升了4倍，客户端软件包的体积缩小了57%，生产环境的 Next.js 应用已经直接跑在上面了。" </p>
</blockquote>
<p>这个 vinext 的<a href="https://github.com/cloudflare/vinext">代码</a>已经放出来了。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022810.webp" title="" /></p>
<p>我觉得，<strong>这件事对 Next.js 的打击非常大</strong>。</p>
<p>Next.js 是 Vercel 公司的产品，背后有一个大型开发团队，每年都是巨额投入，已经整整做了10年。虽然是开源软件，但是企业版、云服务、插件、皮肤都要收费，去年的年收入达到2亿美元。</p>
<p><strong>这种看似难以逾越的护城河，在 AI 面前不堪一击</strong>。一个工程师用了一个星期，就复刻了大团队十年的工作成果，现有的网页应用不改一行代码，放上去就能跑，原版的每个功能都支持。</p>
<p>你知道花了多少钱？Token 费用仅仅为 1100 美元！</p>
<p>这叫 Vercel 怎么再向 Next.js 的开发投钱，客户又怎么愿意再为某个功能付出高昂的使用费。</p>
<p>推而广之，所有的商业软件都受到了重创。<strong>代码的护城河不存在了，只要投入一小笔金钱，AI 就能复刻出大型软件。</strong></p>
<p>那么，为了保护自己，软件公司下一步肯定要防止 AI 复刻。</p>
<p>怎么防呢？<strong>关键就是测试用例</strong>。</p>
<p>Cloudflare 工程师这一次能够复刻成功，主要原因是 Next.js 有完备的文档、庞大的社区文章、以及完整的测试用例。AI 模拟的每一个 API，只要能够通过原有的接口测试，就能确认百分百兼容。</p>
<p>如果拿不到测试用例，谁知道代码行为是否一致，谁敢放到生产环境运行。</p>
<p>可以想象，为了防止复刻，大型软件项目一定会保护自己的测试用例。<strong>测试才是新的护城河。</strong></p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030601.webp" title="" /></p>
<p>世界最流行的数据库 <a href="https://sqlite.org">SQLite</a>，本身代码15.6万行，但是测试用例<a href="https://sqlite.org/testing.html">9205万行</a>，足足大了590倍！</p>
<p>其中，最核心的测试套件 <a href="https://sqlite.org/th3.html">TH3</a> 是闭源的，不公开，主要测试航空、医疗等关键行业的极端情况和边缘案例，属于核心技术资产。正是这些保密用例，才让 SQLite 难以复刻。</p>
<p>无独有偶，就在前两天，另一个开源项目 <a href="https://github.com/tldraw/tldraw/issues/8082">tldraw</a> 也准备将测试用例闭源。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022811.webp" title="" /></p>
<p>说实话，保密的测试用例肯定不利于开源项目的发展，但是开发者需要保护自己的利益。在日益强大的 AI 面前，越来越多的软件可能会选择这样做。</p>
<h2>AI 复刻的版权问题</h2>
<p>AI 复刻软件还有一个版权问题，也引起了<a href="https://tuananh.net/2026/03/05/relicensing-with-ai-assisted-rewrite/">很大争议</a>。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030602.webp" title="" /></p>
<p>Next.js 是最宽松的 MIT 许可证，所以复刻没有版权问题。但是，有人复刻了一个叫做 <a href="https://github.com/chardet/chardet">chardet</a> 的项目，就争议巨大。</p>
<p>chardet 本来采用的许可证，是限制较多的 LGPL，复刻以后改成了 MIT 许可证，引发了原始作者的抗议。</p>
<p>网上的意见也分成了两派。</p>
<p>支持者说，AI 只复刻了功能和接口，代码完全不一样，当然可以更改许可证。</p>
<p>反对者说，GPL 规定了，所有衍生作品都不能更改许可证，AI 复刻就属于衍生。</p>
<p>更麻烦的是，美国法律规定，AI 生成产物无版权，属于公共领域。这意味着，<strong>AI 复刻的软件不能设置许可证，设置了无效。</strong></p>
<p>按照这条法律，软件许可证就意义不大了。管你是什么许可证，任何人 AI 复刻一下就能规避，AI 实现的版本一律没有版权。</p>
<h2>科技动态</h2>
<p>1、<a href="https://decrypt.co/360183/roblox-using-ai-rewrite-chat-swears-slurs-real-time">AI 改写脏话</a></p>
<p>游戏平台 Roblox <a href="https://ir.roblox.com/news/news-details/2026/Roblox-Launches-Real-Time-Chat-Rephrasing-to-Maintain-Civility-and-Gameplay-Flow/default.aspx">宣布</a>，将用 AI 实时修改玩家的对话，让其变得更文明。</p>
<p><i', 5, '阮一峰的网络日志', 'http://www.ruanyifeng.com/blog/2026/03/weekly-issue-388.html', '阮一峰', 'blog', '["\u79d1\u6280", "Weekly", "\u6280\u672f"]', '2026-03-12 23:59:16.000000', '2026-03-16 02:09:33.407276', 'tag:www.ruanyifeng.com,2026:/blog//1.2530', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (32, '零安装的"云养虾"：ArkClaw 使用指南', '一、引言 大家这两天，有没有被"龙虾"（OpenClaw）刷屏？...', '<h2>一、引言</h2>
<p>大家这两天，有没有被"龙虾"（OpenClaw）刷屏？</p>
        <p>到处是它的新闻，就连两会代表和新华社都在谈论。真让人跌破眼镜，一个 AI 软件竟能引起这么大的反响。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031004.webp" title="" /></p>
<p>人们的热情高涨，免费的线下安装活动人满为患，网上的"付费安装"生意兴隆。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031006.webp" title="" /></p>
<p>很多人大概还不知道，现在有一种最简单的龙虾使用方法：<a href="https://www.volcengine.com/docs/82379/2229107?lang=zh">ArkClaw</a>。</p>
<p>简单到你根本不需要操心安装，<strong>因为这是一个免安装的方案</strong>，它直接内置了龙虾，开箱即用。</p>
<p>我也是昨天才开始用，迫不及待跟大家分享，初步使用的感受。没有用过的同学，也可以把它当作《龙虾零门槛上手》教程，看看龙虾到底是怎么回事。</p>
<h2>二、ArkClaw 是什么</h2>
<p>事情是这样的，老读者可能还记得，我在春节前<a href="https://mp.weixin.qq.com/s/e9NvGyPHlQfrUFCXKO4H7A">测评了</a>字节最新发布的 Seed 2.0 模型。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026021416.webp" title="" /></p>
<p>我在文章里说，这是字节目前最强的基础模型，手机豆包用的就是它，测试表现很不错。</p>
<p>字节的同学后来就向我赠送了 <a href="https://www.volcengine.com/activity/codingplan">Coding Plan</a> 套餐，方便继续测试这个模型，各种 AI 编程工具都可以调用它的 API（当然套餐还包含其他国产模型，也是自由使用）。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031007.webp" title="" /></p>
<p>本周一，我突然发现，字节的这个 Coding Plan 套餐开通了一个捆绑服务，就是 ArkClaw。</p>
<p>我问了客服才知道，<strong>只要现在开通 Coding Plan，就能免费使用龙虾</strong>。</p>
<p>也就是说，只要你用字节的 AI 编程套餐，不用多花一分钱，字节就提供一台远程主机，里面安装好了龙虾，你可以自由使用。</p>
<p>需要说明的是，Coding Plan 分成 lite（首月9.9元）和 Pro（首月49.9元）两种套餐。lite 套餐只能免费体验7天，只有 Pro 套餐可以长期使用 ArkClaw。</p>
<h2>三、云养虾</h2>
<p>ArkClaw 属于"云养虾"（又称"云龙虾"），就是把龙虾（OpenClaw）安装在火山方舟（字节的 AI 云服务品牌）的云主机上，它名字里的 ark 就是"方舟"的意思。</p>
<p>除了"云养虾"，也可以把龙虾安装在本地计算机。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031008.webp" title="" /></p>
<p>不了解的朋友可能会好奇，两者有什么区别，我简单说一下。</p>
<p>首先，你要知道<strong>OpenClaw 属于自动化软件</strong>，它的作用就是让用户使用自然语言描述需求，它通过大模型找出满足需求的方法，然后自动去完成。</p>
<p>当它安装在本地计算机（你的笔记本），就方便自动操作本地文件和本地设备，比如"找出拍摄于去年今日的照片"或者"关闭客厅的智能灯，并查询最近一周的耗电量"。</p>
<p>当它安装在云端，就能 7x24 小时跟各种网络服务互动，比如"收到电子邮件时，自动生成30字的内容摘要，向手机发送通知"。</p>
<p>所以，如果你需要自动化操作网络服务，并且需要长时间在线或者每天定时运行，那么就合适使用"云养虾"。</p>
<h2>四、ArkClaw 基本操作</h2>
<h3>4.1 界面</h3>
<p>我给大家看一下，ArkClaw 的样子。</p>
<p>进入<a href="https://console.volcengine.com/ark/region:ark+cn-beijing/experience/claw">控制台</a>，点击"立即创建"，创建一个龙虾实例。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031101.webp" title="" /></p>
<p>创建完成后，就已经安装好了，直接使用。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031102.webp" title="" /></p>
<p>界面非常简洁，就是一个对话框。ArkClaw 对龙虾的官方控制台做了定制，简化了操作界面。</p>
<h3>4.2 抓取信息</h3>
<p>你可以在对话框里面，跟 AI 模型对话，这跟其他模型的用法并无二致。</p>
<p>举例来说，我们可以让它抓取信息。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031103.webp" title="" /></p>
<p>可以看到，由于抓取的是动态内容，所以模型想到了很多实施方案，最后顺利完成。</p>
<p>大家要记住，ArkClaw 就是一台远程主机，任何服务器可以用的技术方案，它都能用，这比安装在一般个人工作电脑上的龙虾更强大。</p>
<h3>4.3 发送消息</h3>
<p>获取信息以后，龙虾可以把这些信息发到手机。</p>
<p>目前，ArkClaw 支持与企业微信、钉钉和飞书绑定。其中，飞书因为是自家的产品，绑定操作最简单，便捷快速，扫码即可。其他两家操作都比较麻烦，具体见<a href="https://www.volcengine.com/docs/6396/2249541?lang=zh">官方文档</a>。</p>
<p>点击对话框上方的"飞书配对"按钮。（前面的"消息渠道"按钮，用于绑定企业微信和钉钉。）</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031104.webp" title="" /></p>
<p>系统会打开一个终端窗口，输出一个二维码，飞书扫描后可以创建一个机器人，跟当前的 ArkClaw 实例绑定。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031105.webp" title="" /></p>
<p>通过这个机器人，你就可以在手机上跟当前这台 ArkClaw 实例对话了。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031106.webp" title="" /></p>
<p>你也可以在电脑上，通过 ArkClaw 网页控制台，向你的手机发消息。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031107.webp" title="" /></p>
<p>电脑端输入上面指令后，手机端就会推送消息（下图）。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031108.webp" title="" /></p>
<h3>4.4 定时任务</h3>
<p>我们还可以规定，龙虾执行某些任务的时间和频率，也就是定时任务。</p>
<p>首先，使用自然语言，在对话框设置定时任务。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026031109.webp" title="" /></p>
<p>设置完成后，你的手机就会每天收到消息了。</p>
<p>如果要删除定时任务，也是使用自然语言发出指', 5, '阮一峰的网络日志', 'http://www.ruanyifeng.com/blog/2026/03/arkclaw.html', '阮一峰', 'blog', '["\u79d1\u6280", "\u6280\u672f", "Developer"]', '2026-03-12 08:01:06.000000', '2026-03-16 02:09:33.407290', 'tag:www.ruanyifeng.com,2026:/blog//1.2529', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (33, '科技爱好者周刊（第 387 期）：你是领先的', '这里记录每周值得分享的科技内容，周五发布。...', '<p>这里记录每周值得分享的科技内容，周五发布。</p>
        <p>本杂志<a href="https://github.com/ruanyf/weekly">开源</a>，欢迎<a href="https://github.com/ruanyf/weekly/issues">投稿</a>。另有<a href="https://github.com/ruanyf/weekly/issues/9088">《谁在招人》</a>服务，发布程序员招聘信息。合作请<a href="mailto:yifeng.ruan@gmail.com">邮件联系</a>（yifeng.ruan@gmail.com）。</p>
<h2>封面图</h2>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030503.webp" title="" /></p>
<p>福州元宵节灯会的福鱼灯，一个25米的机械装置，漂浮在空中。（<a href="http://fj.people.com.cn/n2/2026/0304/c181466-41515232.html">via</a>）</p>
<h2>你是领先的</h2>
<p>世界总人口现在是81亿，如果画成一个<a href="https://www.reddit.com/r/vibecoding/comments/1rbqldk/youre_early/">方块图</a>，每个方块代表320万人。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022615.webp" title="" /></p>
<p>68.8亿人还从没用过 AI（灰色方块），占84%。</p>
<p>13.8亿人跟 AI 有过对话（绿色方块），占16%。</p>
<p>1500万～2500万人付费订阅了 AI 服务（黄色方块），占0.3%。</p>
<p>200万～500万人使用 AI 生成了自己的编程项目（红色方块），占0.04%。</p>
<p>正在阅读这份周刊的你，如果是关注 AI 动态，用过 AI 生成代码，就已经领先全世界99%的人了。</p>
<h2>OpenClaw 的安全</h2>
<p>眼下全世界最火爆的软件，一定属于个人 AI 助手 <a href="https://openclaw.ai/">OpenClaw</a> 。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030302.webp" title="" /></p>
<p>火爆到什么程度？</p>
<p>四个月的时间，它在 GitHub 得到了25万颗星星，超过了 React，成为有史以来<a href="https://www.star-history.com/blog/openclaw-surpasses-react-most-starred-software">星星最多的软件项目</a>。</p>
<p>要知道这些星星，React 用了13年，它只用4个月。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030303.webp" title="" /></p>
<p>上图中，垂直上升的红线就是 OpenClaw，太夸张了。</p>
<p>OpenClaw 的作用，就是通过自然语言控制电脑，完成自动化操作。以前，你需要多种工具和专业技能，才能达到同样的效果。现在只要输入文字或者口述，这不仅有用，也很有趣。</p>
<p>它基本上就是苹果智能助理 Siri 应该有的样子。对于普通用户，这才是与电脑交互的正确方式。可以预料，几年之内，这类工具将会普及到每个人的手机。</p>
<p>但是，它有一个问题：不够安全。</p>
<p>OpenClaw 有40多万行代码、53个配置文件、超过70项依赖，在短短几周内由 AI 生成，没有任何正规的审查流程。</p>
<p>它需要使用你的个人密钥，而且权限极大，完全自主运行。有人把自己的 Apple ID、Gmail 邮箱都授权给它，不敢想象啊，万一出错，会是怎样的后果。</p>
<p>它的防护措施很少，原始设计根本没有，一不小心，还可能暴露在公网上。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030301.webp" title="" /></p>
<p>有人做了一个 <a href="https://openclaw.allegro.earth/">OpenClaw 暴露看板</a>（OpenClaw Exposure Watchboard），收集了所有暴露到公网的 OpenClaw 实例（上图）。你知道现在有多少台？截止到昨天是258305。</p>
<p>你随便选一台机器点进去，就能看到 OpenClaw 控制面板（下图）。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030304.webp" title="" /></p>
<p>那个架设的人，以为正在自动化自己的电脑，哪里料到向全世界敞开了大门。</p>
<p>如果你要用 OpenClaw，至少要安装在虚拟机或者专用的物理机，否则就自求多福吧。</p>
<h2>科技动态</h2>
<p>1、<a href="https://www.theresistornetwork.com/2021/03/qrtape-audio-playback-from-paper-tape.html">二维码纸带</a></p>
<p>一个国外发明家突发奇想，能不能把声音保存在纸带上？</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022303.webp" title="" /></p>
<p>他就把每秒钟的声音，编码后保存成一个二维码，然后把所有二维码依次打印在纸带上。</p>
<p>他又做了一个播放器（下图），外面是纸板，里面是一个传动装置 + 摄像头。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022304.webp" title="" /></p>
<p>播放器会把纸带每秒向前移一格，摄像头识别出二维码的数据，还原成声音，播放出来。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022305.webp" title="" /></p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022306.webp" title="" /></p>
<p>2、<a href="https://www.bleepingcomputer.com/news/security/48m-in-crypto-stolen-after-korean-tax-agency-exposes-wallet-seed/">韩国政府丢失加密货币</a></p>
<p>韩国国税厅抓了一批逃税者，没收了他们的加密货币。</p>
<p>执法部门在网上公布了赃物照片（下图），都是本次行动的战利品。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202603/bg2026030202.webp" title="" /></p>
<p>照片是高清晰度的，里面有一个加密货币的硬件钱包，还有一张纸条，上面手写了钱包的恢复密钥。</p>
<p>结果可想而知，加密货币顿时就被转走了，价值440万美元，大概率找不回来。</p>
<p>这件事凸显了，政府持有加密货币的风险极大，任何一个环节泄漏钱包密码，就全完了。</p>
<p>3、<a href="https://phys.org/news/2026-02-flatfooted-lumbering-rex-tiptoes.html">霸王龙的行走方式</a></p>
<p>霸王龙是一种凶猛的巨型恐龙，白垩纪的王者，也是顶级掠食者。</p>
<p><img alt="" src="https://cdn.beekka.com/blogimg/asset/202602/bg2026022803.webp" title="" /></p>
<p>霸王龙的未解之谜非常多，科学家至今不理解，为什么它的前肢变得又短又小。</p>
<p>最近，科学家又发现了它的一个特点，这么庞大的动物居然是踮着脚的，也就是只用脚尖走路和奔跑。</p>
<p><img alt="" src="https://cdn.beekka.com/blogim', 5, '阮一峰的网络日志', 'http://www.ruanyifeng.com/blog/2026/03/weekly-issue-387.html', '阮一峰', 'blog', '["\u79d1\u6280", "Weekly", "\u6280\u672f"]', '2026-03-05 20:20:54.000000', '2026-03-16 02:09:33.407299', 'tag:www.ruanyifeng.com,2026:/blog//1.2528', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (34, 'LongCat 为 OpenClaw 装上效率引擎：你的自动化任务还能再快 30%', '依赖第三方订阅进行非官方调用存在账号安全风险与服务不稳定性。为规避此类问题，LongCat 团队提供稳定合规的官方免费 API，开发者可通过官方渠道直接接入 OpenClaw，在确保账号安全的前提下构建自动化工作流。', '依赖第三方订阅进行非官方调用存在账号安全风险与服务不稳定性。为规避此类问题，LongCat 团队提供稳定合规的官方免费 API，开发者可通过官方渠道直接接入 OpenClaw，在确保账号安全的前提下构建自动化工作流。', 6, '美团技术团队', 'https://tech.meituan.com/2026/03/09/longcat-openclaw.html', '美团技术团队', 'blog', '["\u6280\u672f", "\u67b6\u6784", "\u540e\u7aef"]', '2026-03-09 00:00:00.000000', '2026-03-16 02:09:34.073759', 'https://tech.meituan.com/2026/03/09/longcat-openclaw.html', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (35, '美团发布基于 N-gram 全新模型：嵌入扩展新范式，实现轻量化 MoE 高效进化', 'LongCat-Flash-Lite是一款拥有 685 亿参数，每次推理仅激活 29 亿~ 45 亿参数的轻量化 MoE 模型。通过将超过 300 亿参数高效用于嵌入层，LongCat-Flash-Lite 不仅超越了参数量等效的 MoE 基线模型，还在与同规模现有模型的对比中展现出卓越的竞争力，尤其在智能体与代码领域表现突出。', 'LongCat-Flash-Lite是一款拥有 685 亿参数，每次推理仅激活 29 亿~ 45 亿参数的轻量化 MoE 模型。通过将超过 300 亿参数高效用于嵌入层，LongCat-Flash-Lite 不仅超越了参数量等效的 MoE 基线模型，还在与同规模现有模型的对比中展现出卓越的竞争力，尤其在智能体与代码领域表现突出。', 6, '美团技术团队', 'https://tech.meituan.com/2026/02/10/longcat-flash-lite.html', '美团技术团队', 'blog', '["\u6280\u672f", "\u67b6\u6784", "\u540e\u7aef"]', '2026-02-10 00:00:00.000000', '2026-03-16 02:09:34.073772', 'https://tech.meituan.com/2026/02/10/longcat-flash-lite.html', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (36, '2025美团技术年货，「马」上到来', '值此马年春节来临之际，我们精选了过去一年美团技术团队微信公众号发布的 40 多篇优质技术文章，精心汇编成一本 500 多页的电子书。谨以此作为一份特别的新年礼物，献给每一位热爱技术、持续探索的同学。', '值此马年春节来临之际，我们精选了过去一年美团技术团队微信公众号发布的 40 多篇优质技术文章，精心汇编成一本 500 多页的电子书。谨以此作为一份特别的新年礼物，献给每一位热爱技术、持续探索的同学。', 6, '美团技术团队', 'https://tech.meituan.com/2026/02/02/2025-spring-festival-present.html', '美团技术团队', 'blog', '["\u6280\u672f", "\u67b6\u6784", "\u540e\u7aef"]', '2026-02-02 00:00:00.000000', '2026-03-16 02:09:34.073781', 'https://tech.meituan.com/2026/02/02/2025-spring-festival-present.html', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (37, '多维创新打造强泛化智能体模型，LongCat-Flash-Thinking-2601技术报告发布', 'LongCat-Flash-Thinking-2601模型创新性地打造了 “重思考模式” ，通过并行推理与深度总结，实现推理宽度与深度的协同扩展，显著提升复杂交互与多步规划任务中的表现。', 'LongCat-Flash-Thinking-2601模型创新性地打造了 “重思考模式” ，通过并行推理与深度总结，实现推理宽度与深度的协同扩展，显著提升复杂交互与多步规划任务中的表现。', 6, '美团技术团队', 'https://tech.meituan.com/2026/02/02/longcat-flash-thinking-2601-techreport.html', '美团技术团队', 'blog', '["\u6280\u672f", "\u67b6\u6784", "\u540e\u7aef"]', '2026-02-02 00:00:00.000000', '2026-03-16 02:09:34.073789', 'https://tech.meituan.com/2026/02/02/longcat-flash-thinking-2601-techreport.html', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (38, '美团 EvoCUA 刷新开源 SOTA，会用电脑还会持续进化的智能体！', '美团技术团队推出了 EvoCUA 模型并在 Github、Huggingface 开源，通过构建可验证数据合成引擎与十万级并发的交互沙盒，将训练范式从传统的“静态轨迹模仿”转变为高效的“经验进化学习”。', '美团技术团队推出了 EvoCUA 模型并在 Github、Huggingface 开源，通过构建可验证数据合成引擎与十万级并发的交互沙盒，将训练范式从传统的“静态轨迹模仿”转变为高效的“经验进化学习”。', 6, '美团技术团队', 'https://tech.meituan.com/2026/01/26/evocua.html', '美团技术团队', 'blog', '["\u6280\u672f", "\u67b6\u6784", "\u540e\u7aef"]', '2026-01-26 00:00:00.000000', '2026-03-16 02:09:34.073797', 'https://tech.meituan.com/2026/01/26/evocua.html', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (39, '美团 LongCat-Flash-Thinking-2601 发布，工具调用能力登顶开源 SOTA！', '美团 LongCat 团队正式对外发布并开源 LongCat-Flash-Thinking-2601。作为已发布的 LongCat-Flash-Thinking 模型的升级版，LongCat-Flash-Thinking-2601 在 Agentic Search（智能体搜索）、Agentic Tool Use（智能体工具调用）、TIR（工具交互推理）等核心评测基准上，均达到开源模型 SOTA 水平。', '美团 LongCat 团队正式对外发布并开源 LongCat-Flash-Thinking-2601。作为已发布的 LongCat-Flash-Thinking 模型的升级版，LongCat-Flash-Thinking-2601 在 Agentic Search（智能体搜索）、Agentic Tool Use（智能体工具调用）、TIR（工具交互推理）等核心评测基准上，均达到开源模型 SOTA 水平。', 6, '美团技术团队', 'https://tech.meituan.com/2026/01/20/longcat-flash-thinking-2601.html', '美团技术团队', 'blog', '["\u6280\u672f", "\u67b6\u6784", "\u540e\u7aef"]', '2026-01-20 00:00:00.000000', '2026-03-16 02:09:34.073806', 'https://tech.meituan.com/2026/01/20/longcat-flash-thinking-2601.html', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (40, 'KuiTest：基于大模型通识的 UI 交互遍历测试', '美团质效技术部联合复旦大学周扬帆教授团队推出 KuiTest——零规则 UI 功能性异常测试工具。KuiTest 通过将“人类预期”直接用作 Test Oracle，解决了长期以来 UI 测试 Oracle 泛化性差的自动化痛点。实验表明，KuiTest 异常召回率达 86%，误报率仅 1.2%，已在执行 21 万+测试用例，发现百余例有效缺陷，大幅降低人工成本并提升测试覆盖率。', '美团质效技术部联合复旦大学周扬帆教授团队推出 KuiTest——零规则 UI 功能性异常测试工具。KuiTest 通过将“人类预期”直接用作 Test Oracle，解决了长期以来 UI 测试 Oracle 泛化性差的自动化痛点。实验表明，KuiTest 异常召回率达 86%，误报率仅 1.2%，已在执行 21 万+测试用例，发现百余例有效缺陷，大幅降低人工成本并提升测试覆盖率。', 6, '美团技术团队', 'https://tech.meituan.com/2026/01/13/kuitest-ui.html', '美团技术团队', 'blog', '["\u6280\u672f", "\u67b6\u6784", "\u540e\u7aef"]', '2026-01-13 00:00:00.000000', '2026-03-16 02:09:34.073814', 'https://tech.meituan.com/2026/01/13/kuitest-ui.html', 0.0, 0);
