INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (104, '玛莎拉蒂母公司Stellantis接洽小米小鹏投资？能双赢吗', '出品|虎嗅汽车组作者|王亚骏头图|视觉中国一张“速通”欧洲的船票，可能已经被摆在了小米小鹏面前。&nbsp;近日，据外媒报道，Stellantis正在与小米小鹏接洽，以寻求这两家造车新势力对其欧洲业务进行投资。据悉，潜在合作事项包括了向中国车企出售玛莎拉蒂等品牌的部分股权、开放欧洲产能。&nbsp;目前，各方的接触已经持续数月，知情人士表示，尚无任何交易达成的确定性。&nbsp;Stellantis是全球第四大车企，总部位于荷兰阿姆斯特丹，由PSA集团和FCA公司在2021年合并而成，旗下拥有玛莎拉蒂、Jeep和标致等14个品牌。Stellantis在法国巴黎西部普瓦西图的一处办公地点；图源：视觉中国此次接洽并非Stellantis首次与造车新势力结缘。2023年10月，Stellantis出资15亿欧元，收购了零跑约20%的股权，此后，双方又于第二年5月成立零跑国际合资公司，这是中国汽车行业首个由中方出技术，外方出渠道反向合资公司。&nbsp;三年前还在投资造车新势力的Stellantis，为何寻求起了小米小鹏的投资？它向新势力们兜售的“旅欧船票”，是否物超所值？本期《车圈脉动》Vo', '<img src="https://img.huxiucdn.com/article/cover/202603/14/215355299532.jpg" />
<p><span class="text-remarks" label="备注">出品|虎嗅汽车组</span></p><p><span class="text-remarks" label="备注">作者|王亚骏</span></p><p><span class="text-remarks" label="备注">头图|视觉中国</span></p><p><br /></p><p>一张“速通”欧洲的船票，可能已经被摆在了小米小鹏面前。</p><p>&nbsp;</p><p>近日，据外媒报道，Stellantis正在与小米小鹏接洽，以寻求这两家造车新势力对其欧洲业务进行投资。据悉，潜在合作事项包括了向中国车企出售玛莎拉蒂等品牌的部分股权、开放欧洲产能。</p><p>&nbsp;</p><p>目前，各方的接触已经持续数月，知情人士表示，尚无任何交易达成的确定性。</p><p>&nbsp;</p><p>Stellantis是全球第四大车企，总部位于荷兰阿姆斯特丹，由PSA集团和FCA公司在2021年合并而成，旗下拥有玛莎拉蒂、Jeep和标致等14个品牌。</p><p><br /></p><p class="img-center-box"><img src="https://img.huxiucdn.com/article/content/202603/14/215605274132.jpg?imageView2/2/w/1000/format/jpg/interlace/1/q/85" /></p><p class="text-img-note" label="图片备注">Stellantis在法国巴黎西部普瓦西图的一处办公地点；图源：视觉中国</p><p><br /></p><p>此次接洽并非Stellantis首次与造车新势力结缘。2023年10月，Stellantis出资15亿欧元，收购了零跑约20%的股权，此后，双方又于第二年5月成立零跑国际合资公司，这是中国汽车行业首个由中方出技术，外方出渠道反向合资公司。</p><p>&nbsp;</p><p>三年前还在投资造车新势力的Stellantis，为何寻求起了小米小鹏的投资？它向新势力们兜售的“旅欧船票”，是否物超所值？本期《车圈脉动》Vol.23，我们来解析一番。</p><p>&nbsp;</p><p class="text-big-title" label="大标题">落魄巨头遇上科技新贵，天作之合？</p><p>&nbsp;</p><p>Stellantis虽贵为全球第四大车企，但当下日子并不算好过。</p><p>&nbsp;</p><p>2025年，Stellantis由盈转亏，净亏损金额达223亿欧元（24年盈利55.2亿欧元）。集团CEO安东尼奥·菲洛萨表示，这份业绩是“我们高估了能源转型速度所带来的代价。”</p><p>&nbsp;</p><p>这份“代价”缘起于四年前。</p><p>&nbsp;</p><p>2022年，Stellantis发布了“Dare Forward 2030”战略规划，力求在2030年拥有超过75款纯电车型，这些车型在全球范围内年销量要达到500万，其中在欧洲售出的所有汽车均为纯电车型，而在美国要有50%。</p><p>&nbsp;</p><p>不过中国市场在这份规划中的地位并不高，Stellantis的计划是在华采取轻资产模式来经营：不建厂，而是将欧美工厂制造的汽车出口到中国。在收入方面，Stellantis希望在2030年从中国市场获取200亿欧元的营收，仅占总收入的6.7%。</p><p>&nbsp;</p><p>不过，事情似乎并未按Stellantis的预测发展。</p><p>&nbsp;</p><p>从2022年到2025年，全球主要汽车市场的新能源汽车发展并不均衡，被Stellantis所忽视的中国市场，新能源渗透率增速远高于欧美。</p><p><br /></p><p class="img-center-box"><img src="https://img.huxiucdn.com/article/content/202603/14/215907777024.jpeg?imageView2/2/w/1000/format/jpeg/interlace/1/q/85" /></p><p class="text-img-note" label="图片备注">图源：乘联会秘书长崔东树</p><p><br /></p><p>而为了配合“Dare Forward 2030”战略规划，Stellantis布局了大量的电池工厂，并对欧洲各地的工厂进行了电动化改造。但由于欧美电动化进程并未迎来狂飙突进式的发展，导致Stellantis如今陷入了产能过剩的窘境。欧洲咨询机构AlixPartners认为，在去年，Stellantis的欧洲工厂的利用率仅为45%。<br /></p><p>&nbsp;</p><p>从理论上看，如果把Stellantis的闲置产能开放给小米小鹏的话，似乎会迎来一个双赢的局面。</p><p>&nbsp;</p><p>首先，Stellantis可以回笼资金，这个没必要做过多解释。</p><p>&nbsp;</p><p>而对于小米和小鹏，它们可以在欧洲获得更多的稳定产能，这有助于降低运输成本和终端的价格，进一步提升车型的竞争力，同时，它们甚至还有可能进入Stellantis在欧洲的销售渠道，获得更广阔的销路。</p><p><br /></p><p>一切真的会这么美好吗？</p><p>&nbsp;</p><p class="text-big-title" label="大标题">蜜糖虽甜，也不能贪多</p><p>&nbsp;</p><p>目前，小米和小鹏在欧洲都没有走到需要扩张产能的阶段。</p><p>&nbsp;</p><p>首先来看小米。小米汽车尚未在欧洲正式开启销售，但欧洲已被确定为出海首站。据公司高管透露，进军欧洲的时间是2027年。</p><p>&nbsp;</p><p>在这种情况下，比较稳妥的方式是先投放高端车型测试市场接受度，然后再考虑是否布局产能。</p><p>&nbsp;</p><p>这一逻辑其实已经被特斯拉验证过。2019年，马斯克宣布将在德国柏林建厂。在此之前，特斯拉旗下高端车型Model&nbsp;S的年销量已经超过了宝马7系和奔驰S级；Model&nbsp;X的年销量则与保时捷卡宴相当。</p><p>&nbsp;</p><p>小鹏方面，去年这家造车新势力的全球出口总量为4.5万辆。以这个量级测算，目前小鹏在欧洲的产能，已经可以覆盖小鹏在当地的销量。</p><p>&nbsp;</p><p>去年第三季度，小鹏首个欧洲本地化生产项目，在奥地利格拉茨麦格纳工厂正式启动。小鹏副董事长兼联席总裁顾宏地曾透露，“在欧洲市场，我们本地生产的车辆数量将达到数万辆。</p><p>&nbsp;</p><p>同时，若贸然扩张生产线，一旦市场波动需收缩产能，车企还要再出一次血。</p><p>&nbsp;</p><p>据AlixPartners估算，在欧洲关闭拥有约1万名员工的大型工厂，需要耗时1至3年，并产生约15亿欧元的费用。</p><p>&nbsp;</p><p>对于造车新势力而言，这是一笔不菲的费用。15亿欧元，约折合人民币118亿元，与之对比，小鹏在2024年全年的研发费用为64.6亿元（小鹏尚未发布2025年全年财报）。</p><p>&nbsp;</p><p>由此可见，欧洲的汽车产能虽然诱人，但若造车新势力一下子吃下太多资产，也容易“消化不良”。</p><p class="text-img-note" label="图片备注"><br /></p><p><a href="http://huxiu.link/ulxE"><strong>下载虎嗅APP</strong></a>，第一时间获取深度独到的商业科技资讯，连接更多创新人群与线下活动</p>', 10, '虎嗅', 'http://www.huxiu.com/article/4842120.html?f=wangzhan', '', 'industry', '["\u79d1\u6280", "\u5546\u4e1a"]', '2026-03-15 02:30:34.000000', '2026-03-16 06:50:56.671808', 'http://www.huxiu.com/article/4842120.html?f=wangzhan', 0.0, 0);
